#!/usr/bin/env bash
set -euo pipefail

usage() {
  cat <<'EOF'
usage: tools/lpc824_flash_restore.sh <backup.bin> [options]

Restore an LPC824 application flash image through the CMSIS-DAP debugprobe.

Options:
  --manifest <file>       Optional manifest file generated by the backup script.
  --flash-start <addr>    Flash base address. Default: 0x00000000
  --adapter-khz <khz>     SWD adapter speed. Default: 100
  --reset-after <mode>    One of: none, halt, run. Default: halt
  --verbose               Print the OpenOCD command line before running it.
  -h, --help              Show this help text.
EOF
}

OPENOCD_BIN=${OPENOCD_BIN:-openocd}
OPENOCD_SCRIPTS=${OPENOCD_SCRIPTS:-/usr/share/openocd/scripts}
PROJECT_CFG=${PROJECT_CFG:-targets/lpc824/openocd/base.cfg}

FLASH_START=${FLASH_START:-0x00000000}
ADAPTER_KHZ=${ADAPTER_KHZ:-100}
RESET_AFTER=${RESET_AFTER:-halt}
MANIFEST_FILE=""
VERBOSE=0
BACKUP_FILE=""

while [ $# -gt 0 ]; do
  case "$1" in
    --manifest)
      shift
      MANIFEST_FILE=${1:-}
      ;;
    --flash-start)
      shift
      FLASH_START=${1:-}
      ;;
    --adapter-khz)
      shift
      ADAPTER_KHZ=${1:-}
      ;;
    --reset-after)
      shift
      RESET_AFTER=${1:-}
      ;;
    --verbose)
      VERBOSE=1
      ;;
    -h|--help)
      usage
      exit 0
      ;;
    -*)
      echo "Unknown option: $1" >&2
      usage >&2
      exit 2
      ;;
    *)
      if [ -n "${BACKUP_FILE}" ]; then
        echo "Unexpected positional argument: $1" >&2
        usage >&2
        exit 2
      fi
      BACKUP_FILE=$1
      ;;
  esac
  shift
done

if [ -z "${BACKUP_FILE}" ]; then
  usage >&2
  exit 2
fi

if [ ! -f "${BACKUP_FILE}" ]; then
  echo "Backup image not found: ${BACKUP_FILE}" >&2
  exit 2
fi

if [ ! -f "${PROJECT_CFG}" ]; then
  echo "OpenOCD config not found: ${PROJECT_CFG}" >&2
  exit 2
fi

if [ -z "${MANIFEST_FILE}" ]; then
  CANDIDATE_MANIFEST="${BACKUP_FILE%.bin}.manifest"
  if [ -f "${CANDIDATE_MANIFEST}" ]; then
    MANIFEST_FILE="${CANDIDATE_MANIFEST}"
  fi
fi

case "${RESET_AFTER}" in
  none|halt|run)
    ;;
  *)
    echo "Invalid --reset-after value: ${RESET_AFTER}. Use none, halt, or run." >&2
    exit 2
    ;;
esac

TIMESTAMP_UTC=$(date -u +"%Y-%m-%dT%H:%M:%SZ")
RESTORE_DIR=$(dirname "${BACKUP_FILE}")
LOG_FILE="${RESTORE_DIR}/lpc824-restore-${TIMESTAMP_UTC}.log"

EXPECTED_SHA=""
if [ -n "${MANIFEST_FILE}" ]; then
  if [ ! -f "${MANIFEST_FILE}" ]; then
    echo "Manifest file not found: ${MANIFEST_FILE}" >&2
    exit 2
  fi
  EXPECTED_SHA=$(grep '^sha256=' "${MANIFEST_FILE}" | head -n 1 | cut -d= -f2- || true)
fi

if [ -n "${EXPECTED_SHA}" ]; then
  ACTUAL_SHA=$(sha256sum "${BACKUP_FILE}" | awk '{print $1}')
  if [ "${ACTUAL_SHA}" != "${EXPECTED_SHA}" ]; then
    echo "SHA-256 mismatch for ${BACKUP_FILE}: expected ${EXPECTED_SHA}, got ${ACTUAL_SHA}." >&2
    exit 3
  fi
fi

OPENOCD_ARGS=(
  -s "${OPENOCD_SCRIPTS}"
  -f "${PROJECT_CFG}"
  -c "adapter speed ${ADAPTER_KHZ}"
  -c "init"
  -c "reset halt"
  -c "flash write_image erase ${BACKUP_FILE} ${FLASH_START}"
  -c "verify_image ${BACKUP_FILE} ${FLASH_START}"
)

case "${RESET_AFTER}" in
  none)
    ;;
  halt)
    OPENOCD_ARGS+=(-c "reset halt")
    ;;
  run)
    OPENOCD_ARGS+=(-c "reset run")
    ;;
esac

OPENOCD_ARGS+=(-c "shutdown")

{
  echo "[${TIMESTAMP_UTC}] lpc824_flash_restore.sh starting"
  echo "[${TIMESTAMP_UTC}] BACKUP_FILE=${BACKUP_FILE}"
  echo "[${TIMESTAMP_UTC}] MANIFEST_FILE=${MANIFEST_FILE:-<none>}"
  echo "[${TIMESTAMP_UTC}] OPENOCD_BIN=${OPENOCD_BIN}"
  echo "[${TIMESTAMP_UTC}] OPENOCD_SCRIPTS=${OPENOCD_SCRIPTS}"
  echo "[${TIMESTAMP_UTC}] PROJECT_CFG=${PROJECT_CFG}"
  echo "[${TIMESTAMP_UTC}] FLASH_START=${FLASH_START}"
  echo "[${TIMESTAMP_UTC}] ADAPTER_KHZ=${ADAPTER_KHZ}"
  echo "[${TIMESTAMP_UTC}] RESET_AFTER=${RESET_AFTER}"
} | tee "${LOG_FILE}"

if [ "${VERBOSE}" -eq 1 ]; then
  printf '[%s] OpenOCD command:' "${TIMESTAMP_UTC}" | tee -a "${LOG_FILE}"
  printf ' %q' "${OPENOCD_BIN}" "${OPENOCD_ARGS[@]}" | tee -a "${LOG_FILE}"
  printf '\n' | tee -a "${LOG_FILE}"
fi

if ! "${OPENOCD_BIN}" "${OPENOCD_ARGS[@]}" 2>&1 | tee -a "${LOG_FILE}"; then
  echo "OpenOCD failed while restoring the LPC824 flash. Check ${LOG_FILE}." >&2
  exit 1
fi

echo "Restore complete:"
echo "  image: ${BACKUP_FILE}"
echo "  log: ${LOG_FILE}"
